#!/usr/bin/env perl
use strict;
use warnings;
use File::Copy;
use File::Path qw(make_path);
use Fcntl qw(:seek);

my $MINIGIT_DIR = '.minigit';

sub mul64 {
    my ($a, $b) = @_;
    my $a_lo = $a & 0xFFFFFFFF;
    my $a_hi = ($a >> 32) & 0xFFFFFFFF;
    my $b_lo = $b & 0xFFFFFFFF;
    my $b_hi = ($b >> 32) & 0xFFFFFFFF;
    my $ll = $a_lo * $b_lo;
    my $cross = (($a_lo * $b_hi) & 0xFFFFFFFF) + (($a_hi * $b_lo) & 0xFFFFFFFF);
    return ($ll & 0xFFFFFFFF) | (((($ll >> 32) + $cross) & 0xFFFFFFFF) << 32);
}

sub minihash {
    my ($data) = @_;
    my $h = 1469598103934665603;
    for my $b (unpack('C*', $data)) {
        $h ^= $b;
        $h = mul64($h, 1099511628211);
    }
    return sprintf('%016x', $h);
}

sub read_file {
    my ($path) = @_;
    open my $fh, '<:raw', $path or return undef;
    local $/;
    my $data = <$fh>;
    close $fh;
    return $data;
}

sub write_file {
    my ($path, $data) = @_;
    open my $fh, '>:raw', $path or die "Cannot write $path: $!\n";
    print $fh $data;
    close $fh;
}

sub cmd_init {
    if (-d $MINIGIT_DIR) {
        print "Repository already initialized\n";
        return;
    }
    make_path("$MINIGIT_DIR/objects");
    make_path("$MINIGIT_DIR/commits");
    write_file("$MINIGIT_DIR/index", '');
    write_file("$MINIGIT_DIR/HEAD", '');
}

sub cmd_add {
    my ($file) = @_;
    unless (defined $file && -f $file) {
        print "File not found\n";
        exit 1;
    }
    my $content = read_file($file);
    my $hash = minihash($content);
    write_file("$MINIGIT_DIR/objects/$hash", $content);

    # Add to index if not already present
    my $index = read_file("$MINIGIT_DIR/index") // '';
    my @lines = grep { $_ ne '' } split /\n/, $index;
    unless (grep { $_ eq $file } @lines) {
        push @lines, $file;
        write_file("$MINIGIT_DIR/index", join("\n", @lines) . "\n");
    }
}

sub cmd_commit {
    my ($message) = @_;
    my $index = read_file("$MINIGIT_DIR/index") // '';
    my @files = grep { $_ ne '' } split /\n/, $index;
    if (!@files) {
        print "Nothing to commit\n";
        exit 1;
    }

    my $head = read_file("$MINIGIT_DIR/HEAD") // '';
    chomp $head;
    my $parent = $head ne '' ? $head : 'NONE';
    my $timestamp = time();

    @files = sort @files;

    my $commit_content = "parent: $parent\n";
    $commit_content .= "timestamp: $timestamp\n";
    $commit_content .= "message: $message\n";
    $commit_content .= "files:\n";
    for my $f (@files) {
        my $blob = read_file($f);
        my $hash = minihash($blob);
        $commit_content .= "$f $hash\n";
    }

    my $commit_hash = minihash($commit_content);
    write_file("$MINIGIT_DIR/commits/$commit_hash", $commit_content);
    write_file("$MINIGIT_DIR/HEAD", $commit_hash);
    write_file("$MINIGIT_DIR/index", '');
    print "Committed $commit_hash\n";
}

sub cmd_log {
    my $head = read_file("$MINIGIT_DIR/HEAD") // '';
    chomp $head;
    if ($head eq '') {
        print "No commits\n";
        return;
    }

    my $current = $head;
    my $first = 1;
    while ($current ne 'NONE' && $current ne '') {
        my $commit_data = read_file("$MINIGIT_DIR/commits/$current");
        unless (defined $commit_data) {
            last;
        }
        my ($parent, $timestamp, $message);
        for my $line (split /\n/, $commit_data) {
            if ($line =~ /^parent: (.*)/) { $parent = $1; }
            elsif ($line =~ /^timestamp: (.*)/) { $timestamp = $1; }
            elsif ($line =~ /^message: (.*)/) { $message = $1; }
        }
        print "\n" unless $first;
        print "commit $current\n";
        print "Date: $timestamp\n";
        print "Message: $message\n";
        $first = 0;
        $current = $parent // 'NONE';
    }
}

# Main
my $cmd = shift @ARGV // '';

if ($cmd eq 'init') {
    cmd_init();
} elsif ($cmd eq 'add') {
    cmd_add(shift @ARGV);
} elsif ($cmd eq 'commit') {
    my $flag = shift @ARGV;
    my $message = shift @ARGV;
    cmd_commit($message);
} elsif ($cmd eq 'log') {
    cmd_log();
} else {
    print "Unknown command: $cmd\n";
    exit 1;
}

