    write_file("$MINIGIT_DIR/HEAD", $commit_hash);
    write_file("$MINIGIT_DIR/index", '');
    print "Committed $commit_hash\n";
}

sub cmd_status {
    my $index = read_file("$MINIGIT_DIR/index") // '';
    my @files = grep { $_ ne '' } split /\n/, $index;
    print "Staged files:\n";
    if (@files) {
        for my $f (@files) {
            print "$f\n";
        }
    } else {
        print "(none)\n";
    }
}

sub cmd_log {
    my $head = read_file("$MINIGIT_DIR/HEAD") // '';
    chomp $head;
    if ($head eq '') {
        print "No commits\n";
        return;
    }

    my $current = $head;
    my $first = 1;
    while ($current ne 'NONE' && $current ne '') {
        my $commit_data = read_file("$MINIGIT_DIR/commits/$current");
        unless (defined $commit_data) {
            last;
        }
        my ($parent, $timestamp, $message);
        for my $line (split /\n/, $commit_data) {
            if ($line =~ /^parent: (.*)/) { $parent = $1; }
