            elsif ($line =~ /^message: (.*)/) { $message = $1; }
        }
        print "\n" unless $first;
        print "commit $current\n";
        print "Date: $timestamp\n";
        print "Message: $message\n";
        $first = 0;
        $current = $parent // 'NONE';
    }
}

sub parse_commit_files {
    my ($commit_data) = @_;
    my %files;
    my $in_files = 0;
    for my $line (split /\n/, $commit_data) {
        if ($line eq 'files:') {
            $in_files = 1;
            next;
        }
        if ($in_files && $line =~ /^(\S+) (\S+)$/) {
            $files{$1} = $2;
        }
    }
    return %files;
}

sub cmd_diff {
    my ($commit1, $commit2) = @_;
    my $data1 = read_file("$MINIGIT_DIR/commits/$commit1");
    unless (defined $data1) {
        print "Invalid commit\n";
        exit 1;
    }
    my $data2 = read_file("$MINIGIT_DIR/commits/$commit2");
    unless (defined $data2) {
        print "Invalid commit\n";
        exit 1;
    }

    my %files1 = parse_commit_files($data1);
    my %files2 = parse_commit_files($data2);

    my %all;
    $all{$_} = 1 for keys %files1;
    $all{$_} = 1 for keys %files2;

    for my $f (sort keys %all) {
        if (!exists $files1{$f} && exists $files2{$f}) {
            print "Added: $f\n";
        } elsif (exists $files1{$f} && !exists $files2{$f}) {
            print "Removed: $f\n";
        } elsif ($files1{$f} ne $files2{$f}) {
            print "Modified: $f\n";
        }
    }
}

sub cmd_checkout {
    my ($commit_hash) = @_;
    my $data = read_file("$MINIGIT_DIR/commits/$commit_hash");
    unless (defined $data) {
        print "Invalid commit\n";
        exit 1;
    }

    my %files = parse_commit_files($data);
    for my $f (sort keys %files) {
        my $blob = read_file("$MINIGIT_DIR/objects/$files{$f}");
        write_file($f, $blob);
    }
    write_file("$MINIGIT_DIR/HEAD", $commit_hash);
    write_file("$MINIGIT_DIR/index", '');
    print "Checked out $commit_hash\n";
}

sub cmd_reset {
    my ($commit_hash) = @_;
    my $data = read_file("$MINIGIT_DIR/commits/$commit_hash");
    unless (defined $data) {
        print "Invalid commit\n";
        exit 1;
    }
    write_file("$MINIGIT_DIR/HEAD", $commit_hash);
    write_file("$MINIGIT_DIR/index", '');
    print "Reset to $commit_hash\n";
}

sub cmd_rm {
    my ($file) = @_;
    my $index = read_file("$MINIGIT_DIR/index") // '';
    my @lines = grep { $_ ne '' } split /\n/, $index;
    my @new = grep { $_ ne $file } @lines;
    if (scalar @new == scalar @lines) {
        print "File not in index\n";
        exit 1;
    }
    if (@new) {
        write_file("$MINIGIT_DIR/index", join("\n", @new) . "\n");
    } else {
        write_file("$MINIGIT_DIR/index", '');
    }
}

sub cmd_show {
    my ($commit_hash) = @_;
    my $data = read_file("$MINIGIT_DIR/commits/$commit_hash");
    unless (defined $data) {
        print "Invalid commit\n";
        exit 1;
    }
    my ($timestamp, $message);
    for my $line (split /\n/, $data) {
        if ($line =~ /^timestamp: (.*)/) { $timestamp = $1; }
        elsif ($line =~ /^message: (.*)/) { $message = $1; }
    }
    my %files = parse_commit_files($data);
    print "commit $commit_hash\n";
    print "Date: $timestamp\n";
    print "Message: $message\n";
    print "Files:\n";
    for my $f (sort keys %files) {
        print "  $f $files{$f}\n";
    }
}

